-- Euro currency update + content repair.
-- All multiline text is rebuilt via char(10) so this file can be pasted
-- into the D1 console without newline loss corrupting the content.

UPDATE articles SET title = 'Чеклист преди да пуснеш проекта си на живо', meta = 'Статия · 5 мин четене', slug = 'cheklist-predi-da-pusnesh-proekta-si-na-zhivo', url = '/statii/cheklist-predi-da-pusnesh-proekta-si-na-zhivo', content = 'Преди да споделиш линка с първите си потребители, мини през този списък. Отнема половин час и спестява неудобни изненади.'||char(10)||''||char(10)||'1. Провери всяка страница на телефон. Повечето посетители идват от мобилно устройство — отвори сайта на своя телефон, не само в тесен прозорец на браузъра.'||char(10)||''||char(10)||'2. Попълни истинско съдържание. Замени всички примерни текстове, имена и снимки. Един „Lorem ipsum“ в продукция подкопава доверието мигновено.'||char(10)||''||char(10)||'3. Тествай формулярите докрай. Изпрати всяка форма с реални данни и провери какво се случва: има ли съобщение за успех, пристига ли записът в базата, какво вижда потребителят при грешка.'||char(10)||''||char(10)||'4. Провери какво се случва без вход. Разгледай сайта в инкогнито прозорец — вижда ли гост нещо счупено или защитено съдържание?'||char(10)||''||char(10)||'5. Настрой заглавия и описания. Всяка страница трябва да има смислен title и description — това е витрината ти в Google и в споделени линкове.'||char(10)||''||char(10)||'6. Пусни го на приятел. Един външен човек за 10 минути намира повече проблеми, отколкото ти за ден. Не му обяснявай нищо — гледай къде се затруднява.'||char(10)||''||char(10)||'7. Направи резервно копие на базата. Преди първите истински потребители си направи навик да експортираш данните. Едно копие седмично е минимум.' WHERE sort = 1;

UPDATE articles SET title = 'Как да свържеш .bg домейн към Lovable проект', meta = 'Ръководство · 8 мин четене', slug = 'kak-da-svarzhesh-bg-domeyn-kam-lovable-proekt', url = '/statii/kak-da-svarzhesh-bg-domeyn-kam-lovable-proekt', content = 'Собственият домейн прави проекта ти истински продукт. Ето процедурата стъпка по стъпка, с особеностите на .bg зоната.'||char(10)||''||char(10)||'Първо купи домейна от регистрар по избор. За .bg домейни има изискване за идентификация — за фирмени регистрации се иска ЕИК, за лични — документ за самоличност. Процесът отнема от няколко часа до ден, планирай го предварително.'||char(10)||''||char(10)||'После отвори настройките на проекта си и добави custom domain. Ще получиш инструкции с два DNS записа: A запис за основния домейн и CNAME за www версията. Въведи ги в DNS панела на регистрара точно както са изписани.'||char(10)||''||char(10)||'Провери записите с dig или онлайн DNS инструмент, преди да чакаш сертификата. Честа грешка е излишна точка или пропуснат поддомейн.'||char(10)||''||char(10)||'SSL сертификатът се издава автоматично, но при .bg домейни това понякога отнема повече време — от опита на общността между 2 и 12 часа е нормално. Ако виси „pending“ повече от денонощие, изтрий домейна от настройките и го добави наново.'||char(10)||''||char(10)||'Накрая настрой пренасочване от www към основния домейн (или обратно), за да имаш един каноничен адрес — това е важно и за SEO.' WHERE sort = 2;

UPDATE articles SET title = '10 грешки на начинаещия и как да ги избегнеш', meta = 'Статия · 7 мин четене', slug = '10-greshki-na-nachinaeshtiya', url = '/statii/10-greshki-na-nachinaeshtiya', content = 'Събрахме най-честите грешки от въпросите в общността. Ако ги избегнеш, ще спестиш дни лутане.'||char(10)||''||char(10)||'1. Искаш всичко наведнъж. Един промпт от 20 изречения дава хаотичен резултат. Строй на малки стъпки.'||char(10)||''||char(10)||'2. Не описваш за кого е продуктът. „Направи ми сайт за салон“ е твърде общо — кажи кой ще го ползва и какво трябва да свърши за 30 секунди.'||char(10)||''||char(10)||'3. Не четеш какво е направил AI-ът. След всяка промяна разгледай резултата, преди да поискаш следващата. Натрупаните непроверени промени се разплитат трудно.'||char(10)||''||char(10)||'4. Пишеш „не работи“ без подробности. Опиши какво направи, какво очакваше и какво се случи вместо това — дословно, с текста на грешката.'||char(10)||''||char(10)||'5. Строиш седмици без да покажеш на никого. Пусни ранна версия на трима познати — обратната връзка ще пренареди приоритетите ти.'||char(10)||''||char(10)||'6. Пазиш всичко в един проект. Експериментите правиш в отделен проект, не върху работещия продукт.'||char(10)||''||char(10)||'7. Игнорираш мобилния изглед. Провери на телефон рано, не в края.'||char(10)||''||char(10)||'8. Отлагаш истинските данни. Свържи база данни веднага щом има какво да се пази — превключването от „наужким“ към истинско е по-лесно рано.'||char(10)||''||char(10)||'9. Забравяш за влизането. Ако продуктът пази лични данни, auth не е „после“ — той определя структурата на всичко останало.'||char(10)||''||char(10)||'10. Отказваш се на третия ден. Всеки в общността е зациклял. Питай — точно за това сме тук.' WHERE sort = 3;

UPDATE articles SET title = 'Речник: AI и no-code термини на български', meta = 'Материал · постоянно обновяван', slug = 'rechnik-ai-i-no-code-termini', url = '/statii/rechnik-ai-i-no-code-termini', content = 'Кратък речник на термините, които ще срещаш постоянно. Обновяваме го при всяко предложение от общността.'||char(10)||''||char(10)||'Промпт (prompt) — текстовата инструкция, която даваш на AI-а. Колкото по-конкретна, толкова по-добър резултатът.'||char(10)||''||char(10)||'Токен (token) — единицата, в която AI моделите измерват текста; една дума е около 1–2 токена. Лимитите и цените се смятат в токени.'||char(10)||''||char(10)||'Кредит (credit) — вътрешната валута на платформата: всяка заявка към AI-а изразходва кредити според сложността.'||char(10)||''||char(10)||'Деплой (deploy) — публикуване на проекта на публичен адрес, достъпен за всички.'||char(10)||''||char(10)||'Бекенд (backend) — невидимата част: база данни, логика, права на достъп. Фронтенд (frontend) — това, което потребителят вижда и докосва.'||char(10)||''||char(10)||'База данни (database) — структурирано хранилище на записите на приложението: потребители, поръчки, публикации.'||char(10)||''||char(10)||'Auth (authentication) — системата за вход и самоличност: кой е потребителят и какво има право да прави.'||char(10)||''||char(10)||'API — начинът две системи да си говорят; например твоят проект пита Stripe „мина ли плащането?“.'||char(10)||''||char(10)||'RLS (Row Level Security) — правила в базата, определящи кой ред от данните кой потребител може да чете или променя.'||char(10)||''||char(10)||'MVP (Minimum Viable Product) — най-малката версия на продукта, която върши истинска работа и може да се тества с истински хора.'||char(10)||''||char(10)||'Итерация (iteration) — един цикъл „поискай → виж резултата → поправи“. Билдването е поредица от итерации, не един голям скок.' WHERE sort = 4;

UPDATE articles SET title = 'Как да си направя Shopify магазин с Lovable?', meta = 'Ръководство · 9 мин четене', slug = 'kak-da-si-napravya-shopify-magazin-s-lovable', url = '/statii/kak-da-si-napravya-shopify-magazin-s-lovable', content = 'Как да си направиш Shopify магазин с Lovable? Кратък отговор: строиш витрината (дизайна и страниците) в Lovable, а Shopify остава двигателят отзад — продукти, наличности, кошница и плащане. Свързваш двете чрез Shopify Storefront API или с вградения Buy Button. Така получаваш пълна свобода върху дизайна, без да губиш надеждния checkout на Shopify.'||char(10)||''||char(10)||'## Кога този подход е за теб'||char(10)||''||char(10)||'Стандартните Shopify теми ограничават: всяка по-смела идея опира до плащане на разработчик или компромис с темплейта. С Lovable описваш витрината с думи — „начална страница с голямо видео, категории като плочки, страница на продукт с галерия и ревюта“ — и я променяш за минути. Shopify продължава да върши това, в което е най-добър: поръчки, наличности, доставки, фактури.'||char(10)||''||char(10)||'## Стъпка 1: Подготви Shopify акаунта'||char(10)||''||char(10)||'В Shopify админа добави продуктите си със снимки, цени и варианти. После създай частно приложение (Settings → Apps and sales channels → Develop apps) и активирай Storefront API — получаваш Storefront access token. Този токен е предназначен за публични витрини и е безопасен за използване във фронтенда, за разлика от Admin API ключовете, които никога не давай на никого.'||char(10)||''||char(10)||'## Стъпка 2: Опиши витрината в Lovable'||char(10)||''||char(10)||'Създай нов проект и опиши магазина: за кого е, какви страници искаш, как да изглежда. После дай на Lovable токена и адреса на магазина с промпт от типа: „Свържи се със Shopify Storefront API на магазин mymagazin.myshopify.com с този Storefront token. Изтегли продуктите с GraphQL и ги покажи в каталог с филтри по категория. Страница на продукт с галерия, варианти и бутон Добави в кошницата.“'||char(10)||''||char(10)||'## Стъпка 3: Кошница и плащане'||char(10)||''||char(10)||'Не изобретявай checkout. Storefront API създава кошница и връща checkout линк — при „Купи“ клиентът отива на защитената страница за плащане на Shopify и се връща при теб след успех. Промптът е прост: „Кошницата да използва Shopify cart API, бутонът за плащане да пренасочва към Shopify checkout.“'||char(10)||''||char(10)||'За съвсем малки магазини има и по-лесен път: Shopify Buy Button. Генерираш embed код за продукт или колекция от Shopify админа и казваш на Lovable къде да го вгради. Без API, без токени — но и с по-малко контрол.'||char(10)||''||char(10)||'## Особености за България'||char(10)||''||char(10)||'Към момента Shopify Payments не се предлага за български магазини, затова в Shopify настрой външен платежен доставчик, работещ с БГ търговци (напр. PayPal или картов гейтуей от списъка на Shopify). Цените си поддържаш в евро, а витрината в Lovable си е изцяло на български — включително SEO заглавията и описанията, които Google вижда.'||char(10)||''||char(10)||'## Чести грешки'||char(10)||''||char(10)||'Не смесвай Admin API с Storefront API — витрината ти трябва само от втория. Не пази наличности и цени на две места — Shopify е единственият източник на истината, Lovable само ги показва. И тествай поръчка от край до край с тестовия режим на платежния доставчик, преди да пуснеш реклама.'||char(10)||''||char(10)||'Ако зациклиш някъде, питай в раздел „Помощ“ — в общността вече има хора с работещи магазини по тази схема.' WHERE sort = 5;

UPDATE articles SET title = 'Как да направя онлайн магазин с Lovable и плащания в евро?', meta = 'Ръководство · 8 мин четене', slug = 'kak-da-napravya-onlayn-magazin-s-lovable', url = '/statii/kak-da-napravya-onlayn-magazin-s-lovable', content = 'Как да направиш онлайн магазин с Lovable и да приемаш плащания в евро? Кратък отговор: строиш магазина в Lovable, пазиш продуктите и поръчките в базата данни на проекта, а плащанията минават през Stripe Checkout с цени в EUR. Без Shopify, без месечни такси за платформа — плащаш само комисионата на Stripe.'||char(10)||''||char(10)||'## Кога собствен магазин вместо Shopify'||char(10)||''||char(10)||'Ако продаваш до няколко десетки продукта и искаш пълен контрол без месечен абонамент, собственият магазин е по-изгодният път. Ако имаш стотици артикули, сложни доставки и склад — виж ръководството ни за Shopify витрина с Lovable.'||char(10)||''||char(10)||'## Стъпка 1: Структурата на магазина'||char(10)||''||char(10)||'Опиши в Lovable какво продаваш и поискай базата данни още в началото: „Онлайн магазин за керамика. Таблица продукти: име, описание, цена в евро, снимки, наличност. Таблица поръчки: клиент, адрес, продукти, статус.“ Ясната структура на данните е половината магазин.'||char(10)||''||char(10)||'## Стъпка 2: Stripe акаунт и продукти'||char(10)||''||char(10)||'Регистрирай фирмата си в Stripe — искат ЕИК, IBAN и данни на представляващия. Създай продуктите ръчно в Stripe панела с цени в EUR и си запиши price ID-тата (започват с price_). От опита на общността: даваш ли на Lovable конкретните price ID-та, checkout-ът работи от първия път.'||char(10)||''||char(10)||'## Стъпка 3: Checkout и поръчки'||char(10)||''||char(10)||'Промптът: „Добави Stripe Checkout: кошница, бутон Плати, който създава checkout сесия с тези price ID-та, валута EUR. След успешно плащане запиши поръчката в базата със статус платена и покажи страница за благодарност. При отказ върни клиента към кошницата.“'||char(10)||''||char(10)||'Важно: записът на поръчката трябва да става при потвърждение от Stripe (webhook), не само при връщането на клиента — иначе затворен браузър значи изгубена поръчка. Помоли изрично: „запиши поръчката чрез Stripe webhook“.'||char(10)||''||char(10)||'## Стъпка 4: Тествай като клиент'||char(10)||''||char(10)||'С тестовите карти на Stripe (4242 4242 4242 4242) мини целия път: разглеждане, кошница, плащане, потвърждение, запис в базата. Пробвай и отказана карта. Чак след това превключи живите ключове.'||char(10)||''||char(10)||'## Документи и доставка'||char(10)||''||char(10)||'За български магазин не забравяй общите условия, политиката за връщане и данните на фирмата в подножието — изисквания на ЗЗП. За доставките започни просто: фиксирана цена и ръчно пускане на пратки; автоматизацията на куриер идва, когато поръчките я оправдаят.'||char(10)||''||char(10)||'Покажи готовия магазин в раздел „Покажи” — обратната връзка от общността хваща пропуски преди първите клиенти.' WHERE sort = 6;

UPDATE articles SET title = 'Как да добавя вход и регистрация в Lovable приложение?', meta = 'Ръководство · 7 мин четене', slug = 'kak-da-dobavya-vhod-i-registratsiya-v-lovable', url = '/statii/kak-da-dobavya-vhod-i-registratsiya-v-lovable', content = 'Как да добавиш вход и регистрация в Lovable приложение? Кратък отговор: казваш на Lovable какви методи за вход искаш — имейл и парола, Google или и двете — и той настройва автентикацията върху вградения бекенд (Supabase). Работещ вход се получава за минути; тънкостите са в redirect адресите и правата на достъп.'||char(10)||''||char(10)||'## Стъпка 1: Опиши какво искаш'||char(10)||''||char(10)||'Промпт, който работи: „Добави автентикация: регистрация и вход с имейл и парола. След вход потребителят вижда своето табло, гостите виждат само началната страница. Бутон Изход в менюто горе вдясно.“ Изброй изрично кое е публично и кое само за влезли — това е най-важното изречение в целия промпт.'||char(10)||''||char(10)||'## Стъпка 2: Вход с Google (по желание)'||char(10)||''||char(10)||'За „Продължи с Google“ ти трябва OAuth приложение в Google Cloud Console: създаваш го, вземаш Client ID и Client Secret и ги поставяш в настройките на автентикацията. Критичната подробност е redirect URL-ът — копирай точния callback адрес, който ти показва бекендът, и го добави в Google Console дословно. Деветдесет процента от проблемите с Google входа са сгрешен redirect.'||char(10)||''||char(10)||'## Стъпка 3: Роли и права'||char(10)||''||char(10)||'Повечето приложения имат поне две нива: потребител и админ. Опиши ги: „Добави роля админ. Админът вижда всички записи и страница за управление. Обикновеният потребител вижда само своите данни.“ Помоли и за правила на ниво база (RLS), не само скрити бутони — скритият бутон не е защита.'||char(10)||''||char(10)||'## Стъпка 4: Тествай сериозно'||char(10)||''||char(10)||'Регистрирай се с временен имейл, излез, влез пак, сбъркай паролата нарочно. Отвори защитена страница като гост през директен линк — трябва да те върне към входа. Влез с два акаунта в два браузъра и провери, че единият не вижда данните на другия.'||char(10)||''||char(10)||'## Чести въпроси'||char(10)||''||char(10)||'Потвърждение на имейл: по подразбиране е включено; за тестове можеш да го спреш, за продукция го върни. Забравена парола: поискай я изрично — „добави забравена парола с линк за смяна по имейл“. Затворена регистрация (само с покана): също се описва с едно изречение.'||char(10)||''||char(10)||'Ако входът ти прави проблеми на собствен домейн, а работи на предишния адрес — провери Site URL и разрешените redirect адреси в настройките на бекенда. Точно този казус се обсъжда редовно в раздел „Помощ“.' WHERE sort = 7;

UPDATE articles SET title = 'Как да свържа база данни към Lovable проект?', meta = 'Ръководство · 7 мин четене', slug = 'kak-da-svarzha-baza-danni-kam-lovable-proekt', url = '/statii/kak-da-svarzha-baza-danni-kam-lovable-proekt', content = 'Как да свържеш база данни към Lovable проект? Кратък отговор: не инсталираш нищо — казваш на Lovable какво да пази и той създава таблиците във вградения бекенд (PostgreSQL чрез Supabase). Твоята работа е да опишеш данните ясно; останалото е промптове.'||char(10)||''||char(10)||'## Кога ти трябва база данни'||char(10)||''||char(10)||'Щом изречението ти съдържа „да се запази“, „списък с“, „потребителят да види своите“ — трябва ти база. Форма за контакт, резервации, поръчки, коментари, любими: всичко това са записи. Не ти трябва за сайт-визитка или лендинг без форми.'||char(10)||''||char(10)||'## Стъпка 1: Опиши данните като таблици'||char(10)||''||char(10)||'Преди да искаш екрани, опиши какво се пази: „Таблица клиенти: име, телефон, имейл. Таблица резервации: клиент, услуга, дата, час, статус (чакаща/потвърдена/отказана).“ Изброй полетата и възможните стойности.'||char(10)||''||char(10)||'Опиши и връзките с прости думи: „Една резервация принадлежи на един клиент. Един клиент има много резервации.“ Формулата „X принадлежи на Y“ е универсалният език, който AI-ът превежда в правилни релации.'||char(10)||''||char(10)||'## Стъпка 2: Поискай екраните върху данните'||char(10)||''||char(10)||'Сега вече: „Форма за нова резервация. Страница със списък на резервациите за деня, филтър по статус. При клик — детайли с бутони Потвърди и Откажи.“ Екраните върху ясна структура излизат точни от първия път.'||char(10)||''||char(10)||'## Стъпка 3: Проверявай данните директно'||char(10)||''||char(10)||'Отвори панела на бекенда и разгледай таблиците след всеки тест — записа ли се формата, попълниха ли се всички полета. Навикът да гледаш данните, а не само интерфейса, хваща тихи грешки рано.'||char(10)||''||char(10)||'## Стъпка 4: Защити данните'||char(10)||''||char(10)||'Данните с лична информация искат правила за достъп (RLS): кой ред кой може да чете и променя. „Всеки потребител вижда само своите резервации; админът вижда всички“ — едно изречение към Lovable, огромна разлика за сигурността. Правило от общността: таблица с лични данни без RLS не отива в продукция.'||char(10)||''||char(10)||'## Ако имаш съществуващи данни'||char(10)||''||char(10)||'Импорт от таблица (Excel/CSV) също се описва: „Добави импорт на клиенти от CSV файл с колони име, телефон, имейл.“ За миграция от друга система питай в общността — вероятно някой вече е минал по същия път.' WHERE sort = 8;

UPDATE articles SET title = 'Как да изпращам имейли от Lovable приложение?', meta = 'Ръководство · 6 мин четене', slug = 'kak-da-izprashtam-imeyli-ot-lovable', url = '/statii/kak-da-izprashtam-imeyli-ot-lovable', content = 'Как да изпращаш имейли от Lovable приложение — потвърждения за поръчка, известия, бюлетин? Кратък отговор: през интеграцията с Resend. Правиш си Resend акаунт, потвърждаваш домейна си с два DNS записа, даваш API ключа на Lovable и описваш кога и какво да се изпраща.'||char(10)||''||char(10)||'## Стъпка 1: Resend акаунт и домейн'||char(10)||''||char(10)||'Регистрирай се на resend.com (безплатният план стига за начало: 100 имейла на ден). Добави домейна си и постави показаните DNS записи (SPF и DKIM) в панела на регистрара. Потвърждението отнема от минути до час. Без потвърден домейн можеш да изпращаш само до собствения си адрес — достатъчно за тестове, недостатъчно за клиенти.'||char(10)||''||char(10)||'## Стъпка 2: Свържи ключа'||char(10)||''||char(10)||'Създай API ключ в Resend и го дай на проекта като секрет — не го пиши в промпт като обикновен текст и никога във фронтенд кода. Lovable пази секретите на сървърната страна (edge функции), където им е мястото.'||char(10)||''||char(10)||'## Стъпка 3: Опиши имейлите'||char(10)||''||char(10)||'Промпт: „При нова поръчка изпращай имейл до клиента от адрес zdravei@moyamarka.bg: потвърждение с номер на поръчката, списък на продуктите и обща сума в евро. Изпращай копие и до мен.“ Опиши тона и съдържанието — темплейтът се генерира.'||char(10)||''||char(10)||'Класика за всяко приложение: потвърждение при регистрация, известие при нова поръчка/резервация (до теб) и потвърждение до клиента. Три имейла покриват повечето нужди на един малък продукт.'||char(10)||''||char(10)||'## Стъпка 4: Тествай доставимостта'||char(10)||''||char(10)||'Изпрати тестове до Gmail и Abv адрес и виж къде пристигат — пощенска кутия или спам. Ако е спам: провери, че DNS записите са потвърдени, че изпращаш от домейна си (не от resend.dev), и че имейлът има смислен текст, не само картинки.'||char(10)||''||char(10)||'## Какво да не правиш'||char(10)||''||char(10)||'Не изпращай маркетингови имейли на хора, които не са се съгласили — освен че е незаконно (GDPR), потапя доставимостта на всичките ти писма. За бюлетин добави изрично съгласие при регистрация и работещ линк за отписване — опиши и двете на Lovable с едно изречение.' WHERE sort = 9;

UPDATE articles SET title = 'Как да добавя AI функции в Lovable приложение?', meta = 'Ръководство · 7 мин четене', slug = 'kak-da-dobavya-ai-funktsii-v-lovable', url = '/statii/kak-da-dobavya-ai-funktsii-v-lovable', content = 'Как да добавиш AI функции в приложение, направено с Lovable — чатбот, автоматични описания, обобщения, категоризация? Кратък отговор: описваш функцията с думи, а Lovable я реализира чрез сървърна (edge) функция, която вика езиков модел. Можеш да ползваш вградения AI на платформата или собствен API ключ.'||char(10)||''||char(10)||'## Какво реално работи добре'||char(10)||''||char(10)||'Най-полезните AI функции в малки продукти са скучните: автоматично описание на продукт от няколко ключови думи, обобщение на дълъг текст, отговори на въпроси върху твоите данни (FAQ бот), категоризиране и приоритизиране на запитвания, извличане на структурирани данни от свободен текст. Започни от една от тях, не от „умен асистент за всичко“.'||char(10)||''||char(10)||'## Стъпка 1: Избери източника на модела'||char(10)||''||char(10)||'Два пътя. Вграденият AI на Lovable е най-бърз за старт — не ти трябва отделен акаунт, разходът върви през кредитите/сметката на проекта. Собствен API ключ (напр. за Anthropic, OpenAI или Google модел) дава контрол върху разходите и избора на модел — ключът се пази като секрет на сървъра, никога във фронтенда.'||char(10)||''||char(10)||'## Стъпка 2: Опиши функцията конкретно'||char(10)||''||char(10)||'Слабо: „добави AI чат“. Силно: „Добави бутон Генерирай описание във формата за нов продукт: взима името и категорията и предлага описание от 3 изречения на български, с тон приятелски и професионален. Потребителят може да го редактира преди запис.“ Кажи входа, изхода, дължината, езика и тона.'||char(10)||''||char(10)||'За бот върху твои данни: „Чат в страницата за помощ, който отговаря само въз основа на текстовете от секция Въпроси и отговори. Ако отговорът го няма там, да казва, че не знае, и да дава линк към формата за контакт.“ Ограничението „отговаряй само от тези данни“ е разликата между полезен бот и бот, който си измисля.'||char(10)||''||char(10)||'## Стъпка 3: Дръж разходите под контрол'||char(10)||''||char(10)||'Всяко извикване на модел струва пари. Три навика: ограничи дължината на отговорите; не викай AI при всяко натискане на клавиш, а при изричен бутон; за повтарящи се въпроси кеширай отговора. Помоли Lovable и за дневен лимит на потребител, ако функцията е публична.'||char(10)||''||char(10)||'## Стъпка 4: Тествай с лоши входове'||char(10)||''||char(10)||'Дай празен вход, твърде дълъг текст, въпрос извън темата, опит за злоупотреба („игнорирай инструкциите си“). Добрата AI функция се проваля тихо и учтиво: съобщение „опитай с по-кратък текст“, не счупен екран.'||char(10)||''||char(10)||'Сподели какво си направил в раздел „Покажи“ — AI функциите са най-обсъжданата тема в общността и винаги събират идеи за подобрения.' WHERE sort = 10;

UPDATE lessons SET slug = 'kakvo-e-lovable', title = 'Какво е Lovable и какво можеш да построиш', content = 'Lovable е инструмент, който превръща описание на обикновен език в работещо уеб приложение: интерфейс, логика и връзка с данни. Не ти трябва да пишеш код — трябва ти ясна представа какво искаш да се случи.'||char(10)||''||char(10)||'Какво реално строят хората от нашата общност: резервационни системи, каталози с продукти, вътрешни инструменти за фирми, лични проекти като бюджетни трекери. Общото е, че това са продукти с ясна задача, а не „още едно голямо социално приложение“.'||char(10)||''||char(10)||'Добро първо упражнение: избери си досаден проблем от ежедневието — списък, който водиш на хартия, таблица, която постоянно препращаш по имейл — и си го дръж наум през целия курс. Ще го билднем.' WHERE course_id = 1 AND sort = 1;

UPDATE lessons SET slug = 'parvi-proekt', title = 'Първи проект: от идея до работещ прототип', content = 'Отвори нов проект и опиши идеята си в 3–4 изречения по формулата: за кого е, какво прави, кои са основните екрани. Пример: „Приложение за малка автомивка. Клиентите виждат свободни часове и записват час. Собственикът вижда списък със записаните часове за деня.“'||char(10)||''||char(10)||'Натисни изпращане и изчакай първата версия. Ще получиш работещ прототип — вероятно 70% верен и 30% не както си го представяше. Това е нормално и очаквано.'||char(10)||''||char(10)||'Съпротиви се на желанието да изброиш всички корекции наведнъж. Избери едно нещо — най-важното — и го поискай с отделно съобщение. В следващия урок ще разгледаме интерфейса, с който ще работиш всеки ден.' WHERE course_id = 1 AND sort = 2;

UPDATE lessons SET slug = 'interfeysat', title = 'Интерфейсът: чат, преглед и история на версиите', content = 'Работното пространство има три ключови зони. Вляво е чатът — там описваш какво искаш. Вдясно е прегледът на приложението — той е жив, можеш да кликаш и тестваш направо в него. И историята на версиите — списък на всички промени, към които можеш да се върнеш.'||char(10)||''||char(10)||'Историята е предпазната ти мрежа. Преди по-смела промяна си отбележи докъде си стигнал; ако резултатът не ти хареса, връщаш се с един клик, вместо да „поправяш поправката“ с още промптове — най-честият начин начинаещите да си оплетат проекта.'||char(10)||''||char(10)||'Упражнение: направи три малки промени (цвят, текст на бутон, ново поле), после върни средната. Усвои ли това, вече не можеш да счупиш нищо необратимо.' WHERE course_id = 1 AND sort = 3;

UPDATE lessons SET slug = 'kak-govorim-s-ai', title = 'Как да „говорим“ с AI — основни принципи', content = 'Три принципа покриват 80% от успешната комуникация с AI-а.'||char(10)||''||char(10)||'Първо: описвай резултата, не изпълнението. Вместо „сложи div с флекс и три колони“ кажи „искам цените в три колони една до друга, средната откроена“. AI-ът е по-добър в техническите решения, отколкото ти в техническите термини.'||char(10)||''||char(10)||'Второ: давай контекст. „Бутонът е твърде голям“ е по-слабо от „бутонът за резервация в началната страница е твърде голям на телефон“.'||char(10)||''||char(10)||'Трето: истинско съдържание. Ако искаш сайт за пекарна, дай истински имена на продукти и истински цени в промпта. С примерни данни („Продукт 1, Продукт 2“) целият дизайн излиза генеричен.' WHERE course_id = 1 AND sort = 4;

UPDATE lessons SET slug = 'malki-stapki', title = 'Малки стъпки, чести проверки', content = 'Най-важният работен навик: една промяна — една проверка. Изпращаш заявка, разглеждаш резултата в прегледа, чак тогава следващата. Звучи бавно, но е в пъти по-бързо от разплитането на пет натрупани промени, две от които са се счупили взаимно.'||char(10)||''||char(10)||'Дръж си списък със задачи извън инструмента — на хартия или в бележник. След всяка проверка задраскваш ред и избираш следващия. Това те пази и от „скитане“ — синдрома да подобряваш цветове три часа, докато формата за поръчка още не работи.'||char(10)||''||char(10)||'Правило от общността: ако три поредни промпта по един проблем не дават резултат, спри. Върни се към последната добра версия и опиши проблема наново, отначало, с повече контекст.' WHERE course_id = 1 AND sort = 5;

UPDATE lessons SET slug = 'izobrazheniya-i-brandirane', title = 'Работа с изображения и брандиране', content = 'Можеш да качваш собствени изображения — лого, снимки на продукти, фонове — и да казваш на AI-а къде да ги използва. Качественото лого и 3–4 истински снимки вдигат вида на проекта повече от всякакви ефекти.'||char(10)||''||char(10)||'За цветовете давай конкретика: „основен цвят тъмнозелено, акцент топло жълто, фон почти бяло“. Още по-добре — дай референция: „цветова схема като на еди-кой-си сайт, но по-мека“.'||char(10)||''||char(10)||'Шрифтовете остави на инструмента, освен ако брандът ти няма изисквания. Ако имаш брандбук — опиши го в един промпт в началото на проекта и помоли AI-а да го спазва занапред: това настройва всички следващи промени.' WHERE course_id = 1 AND sort = 6;

UPDATE lessons SET slug = 'kogato-neshto-se-schupi', title = 'Когато нещо се счупи: как да опишеш грешката', content = 'Грешките са част от процеса — разликата между начинаещ и опитен билдър е в описанието им.'||char(10)||''||char(10)||'Работеща формула от три части: какво направих („попълних формата за контакт и натиснах Изпрати“), какво очаквах („съобщение за успех“), какво се случи („страницата се презареди и всичко от формата изчезна“). Ако на екрана има текст на грешка — препиши го дословно, той е най-ценната следа.'||char(10)||''||char(10)||'Избягвай „не работи“, „счупи се“, „нещо стана“ — те принуждават AI-а да гадае, а грешното предположение води до грешна „поправка“ върху здрав код.'||char(10)||''||char(10)||'При заплетен случай питай и в раздел „Помощ“ на общността — с добро описание по формулата обикновено получаваш отговор за минути.' WHERE course_id = 1 AND sort = 7;

UPDATE lessons SET slug = 'publikuvane', title = 'Публикуване и споделяне на проекта', content = 'Публикуването става с един бутон — проектът получава публичен адрес и всеки с линка може да го ползва. Оттук нататък мисли за две версии: публикуваната (която хората виждат) и работната (в която строиш). Промените стигат до публичната чак когато публикуваш отново.'||char(10)||''||char(10)||'Преди първото споделяне мини през краткия чеклист: провери на телефон, тествай формите с истински данни, разгледай като гост в инкогнито прозорец.'||char(10)||''||char(10)||'Собственият домейн (напр. twoyproekt.bg) се добавя от настройките — имаме отделно ръководство за .bg домейни в раздел Обучение.'||char(10)||''||char(10)||'Финално упражнение: публикувай проекта от курса и пусни линка в раздел „Покажи“ на общността. Обратната връзка от първите десет души струва повече от още седмица самотно билдване.' WHERE course_id = 1 AND sort = 8;

UPDATE lessons SET slug = 'anatomiya-na-dobria-prompt', title = 'Анатомия на добрия промпт', content = 'Добрият промпт има четири части: контекст (какъв е продуктът и за кого), задача (какво да се направи), детайли (изисквания, които не са очевидни) и ограничения (какво да НЕ се пипа).'||char(10)||''||char(10)||'Слаб промпт: „Добави отзиви.“'||char(10)||''||char(10)||'Силен промпт: „Сайтът е за счетоводна къща с малки фирми за клиенти. Добави секция с 3 клиентски отзива на началната страница, под услугите. Всеки отзив: цитат, име и фирма. Дизайнът да остане както е — не пипай нищо друго.“'||char(10)||''||char(10)||'Разликата не е в дължината, а в това, че вторият не оставя място за гадаене. Упражнение: вземи последния си слаб промпт и го пренапиши по четирите части.' WHERE course_id = 2 AND sort = 1;

UPDATE lessons SET slug = 'kontekst-i-referentsii', title = 'Контекст и референции: „като X, но…“', content = 'Най-краткият път към добър дизайн е референцията. „Направи ценовата страница като на познат SaaS продукт — три плана, средният откроен — но с нашите цветове и в евро“ дава по-добър резултат от 15 реда описание.'||char(10)||''||char(10)||'Референцията работи, защото извиква у AI-а цялостен модел: подредба, разстояния, йерархия. Ти добавяш само отклоненията.'||char(10)||''||char(10)||'Втори похват — антиреференция: „да НЕ прилича на корпоративен банков сайт, търсим топло и лично усещане“. Изключването на посока също е информация.'||char(10)||''||char(10)||'Внимавай с прекомерната вярност: искаш „в духа на“, не копие. Добавяй винаги какво е различното при теб — иначе получаваш безличен клонинг.' WHERE course_id = 2 AND sort = 2;

UPDATE lessons SET slug = 'iteratsii-bez-schupvane', title = 'Итерации: как да поискаш промяна, без да счупиш друго', content = 'Най-честата фрустрация: искаш малка промяна, а се променят три други неща. Решението е в изричното ограничаване на обхвата.'||char(10)||''||char(10)||'Винаги казвай къде: „в началната страница, в горната секция“ вместо „горе“. Винаги казвай какво да остане: „останалото не се пипа“. Тези две изречения спестяват половината проблеми.'||char(10)||''||char(10)||'При промяна на съществуващо поведение описвай и старото, и новото: „сега при клик върху продукт се отваря нова страница; искам вместо това страничен панел, без презареждане“.'||char(10)||''||char(10)||'И правилото от основния курс важи двойно тук: една промяна на промпт. „Оправи менюто, смени цветовете и добави търсене“ е три промпта, слети в един — и трите излизат наполовина.' WHERE course_id = 2 AND sort = 3;

UPDATE lessons SET slug = 'strukturata-na-dannite', title = 'Структура на данните в промпта', content = 'Когато проектът пази записи — продукти, клиенти, резервации — опиши ги като таблици, преди да искаш екрани. AI-ът строи в пъти по-точно върху ясна структура.'||char(10)||''||char(10)||'Формат, който работи: „Резервация: клиентско име, телефон, услуга (от списък), дата, час, статус (чакаща/потвърдена/отказана).“ Изброй полетата и откъде идват стойностите им.'||char(10)||''||char(10)||'Опиши и връзките: „Всяка резервация е за една услуга. Една услуга има много резервации.“ Звучи академично, но именно това пази от дублирани и разпилени данни после.'||char(10)||''||char(10)||'Ако не си сигурен в структурата — питай самия AI: „Какви таблици и полета предлагаш за система за резервации на автомивка?“ Прегледай предложението, поправи го и чак тогава искай екраните.' WHERE course_id = 2 AND sort = 4;

UPDATE lessons SET slug = 'promptove-za-dizayn', title = 'Промптове за дизайн и UI', content = 'Дизайнерските промптове страдат от общи думи: „модерно“, „чисто“, „красиво“ значат различно за всеки. Заменяй ги с осезаеми решения.'||char(10)||''||char(10)||'Вместо „модерен дизайн“: „много бяло пространство, едър заглавен шрифт, заоблени ъгли, мека сянка на картите“. Вместо „да е приятно“: „топли цветове — керемидено и крем, никакво студено синьо“.'||char(10)||''||char(10)||'Изброй емоцията чрез сравнение: „да усещаш доверие като при лекар, не енергия като при фитнес“. Емоционалните котви подреждат стотици малки решения наведнъж.'||char(10)||''||char(10)||'И задължителното: „всичко на български, истинско съдържание, без примерни латински текстове“. Едно изречение — огромна разлика в крайния вид.' WHERE course_id = 2 AND sort = 5;

UPDATE lessons SET slug = 'cheklist-promptove', title = 'Чеклист промптове за преди пускане', content = 'Финалните промптове преди публикуване са различни от строителните — те са проверовъчни. Ето комплект за копиране:'||char(10)||''||char(10)||'„Прегледай всички страници на телефон и оправи всичко, което се чупи или е твърде дребно за докосване.“'||char(10)||''||char(10)||'„Провери всички форми: всяка да има съобщение при успех и ясна грешка при празни или невалидни полета.“'||char(10)||''||char(10)||'„Добави заглавие и описание за търсачки на всяка страница, на български, с истинските имена на продукта.“'||char(10)||''||char(10)||'„Прегледай сайта като нерегистриран посетител и ми кажи какво вижда и какво не.“'||char(10)||''||char(10)||'Пускай ги един по един и проверявай след всеки. Този половин час е разликата между „пуснах го“ и „пуснах го и не ме е срам“.' WHERE course_id = 2 AND sort = 6;

UPDATE lessons SET slug = 'zashto-baza-danni', title = 'Защо ти трябва база данни', content = 'Без база данни проектът ти е брошура: изглежда добре, но не помни нищо. Регистрация, поръчка, резервация, коментар — всичко това са записи, които трябва да живеят някъде между посещенията.'||char(10)||''||char(10)||'Supabase е базата, която общността най-често ползва с Lovable: истински PostgreSQL с готова система за вход, права на достъп и удобен панел за разглеждане на данните. Безплатният план стига за учене и за първите истински потребители.'||char(10)||''||char(10)||'Кога ти трябва: щом в изреченията ти се появят „потребителят да може да запази…“, „собственикът да вижда списък с…“. Кога не ти трябва: сайт-визитка, портфолио, лендинг без форми.'||char(10)||''||char(10)||'В този курс ще стигнем от нулата до работещ вход и плащане в евро.' WHERE course_id = 3 AND sort = 1;

UPDATE lessons SET slug = 'sazdavane-na-supabase-proekt', title = 'Създаване на Supabase проект', content = 'Регистрирай се на supabase.com (входът с GitHub е най-бърз). Създай нова организация — за лични проекти името няма значение — и в нея нов проект.'||char(10)||''||char(10)||'Три решения при създаването: име на проекта (каквото искаш), парола за базата (генерирай силна и я запиши в мениджър на пароли — трудно се сменя после) и регион. Избери Frankfurt (eu-central-1) — най-близкият до България, а близостта се усеща в скоростта на всяка заявка.'||char(10)||''||char(10)||'След минута-две проектът е готов. Разгледай панела: Table Editor (данните като таблици), Authentication (потребителите) и Settings → API, откъдето по-късно ще ти трябват адресът на проекта и публичният ключ. Не споделяй service_role ключа с никого и никъде.' WHERE course_id = 3 AND sort = 2;

UPDATE lessons SET slug = 'svarzvane-s-lovable', title = 'Свързване на Supabase с Lovable', content = 'Свързването става от интеграциите на проекта: избираш Supabase, оторизираш се и посочваш кой Supabase проект да се върже. Оттук нататък Lovable може сам да създава таблици и да чете/пише данни.'||char(10)||''||char(10)||'След свързването опиши в промпт какво да се съхранява: „Свържи формата за резервации с базата: запис с име, телефон, услуга, дата и час. Покажи ми списък на записите в админ страница.“'||char(10)||''||char(10)||'Провери резултата откъм Supabase: отвори Table Editor и виж дали записът от тестовата ти форма е там. Навикът да поглеждаш данните директно в базата хваща проблеми, които не се виждат от интерфейса.'||char(10)||''||char(10)||'Ако нещо не тръгва, най-честата причина е, че интеграцията е направена към грешен Supabase проект — провери в настройките.' WHERE course_id = 3 AND sort = 3;

UPDATE lessons SET slug = 'tablitsi-i-relatsii', title = 'Таблици и релации — основи', content = 'Мисли за таблиците като за листове в тетрадка: един лист = един вид нещо. Клиенти на един лист, услуги на друг, резервации на трети. Всеки ред има уникален номер (id), а връзките между листовете стават чрез тези номера: резервацията пази id на клиента и id на услугата.'||char(10)||''||char(10)||'Златно правило: не дублирай. Ако името на клиента живее в таблицата клиенти, в резервацията стои само номерът му, не и копие на името. Иначе при смяна на името ще имаш две истини.'||char(10)||''||char(10)||'Опиши това на AI-а с думи: „Резервация принадлежи на клиент и на услуга.“ Формулировката „X принадлежи на Y“ / „Y има много X“ е универсалният език за релации и Lovable я разбира отлично.' WHERE course_id = 3 AND sort = 4;

UPDATE lessons SET slug = 'vhod-s-imeyl', title = 'Вход с имейл и парола', content = 'Включи имейл входа от Authentication → Providers в Supabase (обикновено е включен по подразбиране). После опиши в Lovable: „Добави регистрация и вход с имейл и парола през Supabase. След вход потребителят вижда своите резервации. Изход от менюто горе вдясно.“'||char(10)||''||char(10)||'Реши какво е задължително: може ли гост да разглежда? Кое е само за влезли? Опиши го изрично — „резервация може да прави само влязъл потребител, разглеждането е свободно“.'||char(10)||''||char(10)||'Тествай с временен имейл (има безплатни услуги за еднократни адреси): регистрация, изход, вход, грешна парола. Провери в Supabase → Authentication → Users, че потребителят се е появил.'||char(10)||''||char(10)||'Внимание: по подразбиране Supabase иска потвърждение на имейла. За тестове можеш да го изключиш от настройките, за продукция го остави включено.' WHERE course_id = 3 AND sort = 5;

UPDATE lessons SET slug = 'vhod-s-google', title = 'Вход с Google', content = 'Входът с Google маха най-голямото триене при регистрация — половината хора се отказват на „измисли си парола“.'||char(10)||''||char(10)||'Настройката има две страни. В Google Cloud Console създаваш OAuth приложение и получаваш Client ID и Client Secret. В Supabase → Authentication → Providers → Google ги поставяш и включваш провайдъра.'||char(10)||''||char(10)||'Критичната подробност, която спъва всички: redirect URL-ът. Supabase ти показва точен адрес (…supabase.co/auth/v1/callback) — той трябва да е вписан в Google Console дословно. При собствен домейн добави и него в разрешените адреси в Supabase (Site URL и Redirect URLs).'||char(10)||''||char(10)||'После в Lovable: „Добави бутон Вход с Google до формата за вход.“ Тествай и на публикувания адрес, не само в прегледа — OAuth е чувствителен към точния домейн.' WHERE course_id = 3 AND sort = 6;

UPDATE lessons SET slug = 'rls-s-prosti-dumi', title = 'Права на достъп (RLS) с прости думи', content = 'Row Level Security звучи страшно, а идеята е проста: правила кой ред от таблицата кой може да вижда и променя. Без RLS всеки достатъчно любопитен посетител може да прочете цялата ти база — включително чуждите резервации с телефони.'||char(10)||''||char(10)||'Основните правила се описват с думи: „Всеки влязъл потребител вижда само своите резервации. Само админ вижда всички. Гости не виждат нищо от таблицата клиенти.“ Кажи това на Lovable и помоли да включи RLS за всички таблици с лични данни.'||char(10)||''||char(10)||'Провери резултата грубо: влез с два различни акаунта и се увери, че единият не вижда данните на другия. После погледни в Supabase → Table Editor → полицата на таблицата, че RLS е Enabled.'||char(10)||''||char(10)||'Правилото е желязно: таблица с лични данни без RLS не отива в продукция.' WHERE course_id = 3 AND sort = 7;

UPDATE lessons SET slug = 'stripe-podgotovka', title = 'Stripe: подготовка на акаунта', content = 'Stripe е стандартът за картови плащания и работи отлично за български фирми. Регистрацията иска данни за бизнеса: ЕИК, IBAN и лични данни на представляващия. Активацията отнема от часове до няколко дни — стартирай я рано, тестовият режим работи и междувременно.'||char(10)||''||char(10)||'Тестов срещу жив режим: Stripe има два напълно отделни свята, всеки със свои ключове. Всичко се строи и тества в тестовия; на живо се минава чак накрая с една смяна на ключовете.'||char(10)||''||char(10)||'Създай продуктите ръчно в Stripe панела — име, цена, валута — вместо да оставяш това на промптове. Така получаваш конкретни price ID-та, които после даваш на Lovable дословно. От опита на общността: това е разликата между „проработи от първия път“ и следобед дебъгване.' WHERE course_id = 3 AND sort = 8;

UPDATE lessons SET slug = 'plashtaniya-v-evro', title = 'Плащания в евро: валути и checkout', content = 'Създай цените в Stripe в EUR — валутата се избира на ниво цена, не на ниво акаунт. Ако таргетираш и пазари извън еврозоната, добави за същия продукт и цена в съответната валута.'||char(10)||''||char(10)||'После в Lovable: „Добави плащане със Stripe Checkout за услугата X, price ID: price_…, валута EUR. След успешно плащане — страница за благодарност и запис на поръчката в базата. При отказ — връщане към кошницата със съобщение.“'||char(10)||''||char(10)||'Клопката, за която всички се спъват: ако не посочиш изрично валутата и price ID-то, checkout сесията често излиза в USD с генерична цена. Дословният price ID решава това.'||char(10)||''||char(10)||'Тествай с тестовите карти на Stripe (4242 4242 4242 4242 за успех, има и специални номера за откази) — работят и за EUR.' WHERE course_id = 3 AND sort = 9;

UPDATE lessons SET slug = 'testvane-i-puskane', title = 'Тестване и пускане на живо', content = 'Финалната права. Мини по цялата верига в тестов режим: регистрация → вход → действие (резервация/поръчка) → плащане с тестова карта → записът се появява в Supabase → потребителят вижда потвърждение. Всяко звено поотделно и после всичко заедно, на публикувания адрес.'||char(10)||''||char(10)||'Провери и грешните пътища: отказана карта, затворен по средата checkout, двойно натискане на бутона за плащане.'||char(10)||''||char(10)||'Пускането на живо е кратък списък: смени Stripe ключовете от тестови на живи, включи потвърждението на имейл в Supabase, увери се, че RLS е навсякъде, и направи едно истинско плащане с истинска карта на минимална сума — после си го възстанови от Stripe панела.'||char(10)||''||char(10)||'Поздравления — имаш продукт с истински данни, вход и плащания. Сподели го в раздел „Покажи“!' WHERE course_id = 3 AND sort = 10;

UPDATE news SET excerpt = 'Разбивка на плановете в евро, кой план за какъв тип проект е подходящ и как да оптимизирате кредитите си.', body = 'Новите планове предизвикаха доста въпроси в общността, затова направихме разбивка в евро и с примери от реални проекти.'||char(10)||''||char(10)||'Безплатният план остава подходящ за учене и експерименти: дневният лимит кредити стига за няколко часа активно билдване. Ако сте в началото — започнете оттук и не бързайте с ъпгрейд.'||char(10)||''||char(10)||'Персоналният план (около 23 €/месец) е сладката точка за повечето хора в общността: месечните кредити стигат за развитие на един активен проект плюс поддръжка на втори. Тук са и custom домейните — задължителни за истински продукт.'||char(10)||''||char(10)||'Екипните планове имат смисъл от трима души нагоре — плащате на място, а кредитите са общи, което на практика излиза по-изгодно от отделни персонални планове.'||char(10)||''||char(10)||'Съвети за оптимизиране на кредити от опита на общността: правете по-малки, конкретни заявки вместо огромни промптове; ползвайте историята на версиите вместо да „поправяте с още промптове“; и дръжте експериментите в отделен проект, за да не горите кредити по продукционния.' WHERE slug = 'obnoveni-tseni-i-kakvo-oznachavat-za-vas';

UPDATE news SET excerpt = 'Гордост! Разгледайте проектите на Ива, Стоян и екипа на „Пазарувай локално“ — и какво можем да научим от тях.', body = 'Гордост! В световната витрина на Lovable този месец попаднаха три проекта с български автори — признание, което досега се беше случвало едва на шепа проекти от региона.'||char(10)||''||char(10)||'Ива Стоянова влиза с платформата си за управление на малки счетоводни къщи — проект, който показа как един човек с добро познаване на нишата може да измести утвърден софтуер. Стоян Колев е във витрината с резервационната си система, започната като помощ за фризьорския салон на сестра му и вече използвана от десетки обекти. Третият проект е „Пазарувай локално“ — екипна разработка, свързваща квартални магазини с клиенти в района.'||char(10)||''||char(10)||'Какво е общото между трите? Всички са започнали от конкретен, тесен проблем на истински хора, а не от „идея за приложение“. И тримата автори са активни в нашата общност — ще ги поканим на следващата среща в София да разкажат повече.'||char(10)||''||char(10)||'Разгледайте проектите, дайте им глас във витрината и питайте авторите в коментарите!' WHERE slug = 'tri-balgarski-proekta-v-svetovnata-lovable-vitrina';

UPDATE news SET excerpt = 'Обобщихме последните подобрения за споделени проекти и как да ги използвате с вашия екип. Включва кратко видео на български.', body = 'Екипите бяха една от най-чаканите възможности и последните обновления най-после ги правят практични за ежедневна работа. Обобщаваме какво е новото и как да го използвате с вашия екип.'||char(10)||''||char(10)||'Споделените проекти вече позволяват няколко души да работят по един продукт, без да си пречат: всеки вижда кой какво е променил, а историята на версиите позволява безболезнено връщане назад. За малките екипи това означава, че дизайнерът може да пипа изгледа, докато друг човек описва логиката — паралелно.'||char(10)||''||char(10)||'Правата на достъп са разделени на роли: собственик, редактор и наблюдател. Наблюдателят е особено полезен за клиенти — виждат прогреса на живо, без да могат да счупят нещо.'||char(10)||''||char(10)||'Подготвихме и кратко видео на български, в което показваме как да организирате екипен проект от нулата: линкът е в дискусията към тази новина. Ако вече ползвате екипните функции, споделете опита си в коментарите — събираме добри практики за следващ материал.' WHERE slug = 'novi-vazmozhnosti-za-ekipna-rabota-v-lovable';

UPDATE posts SET title = 'Направих бюджетен трекер за семейството — фийдбек?', slug = 'napravih-byudzheten-treker-za-semeystvoto-fiydbek', excerpt = 'Две вечери работа: общ бюджет, категории на български и графика по месеци. Чакам критика.', body = 'Жена ми искаше просто приложение за семейния бюджет без абонамент. Направих го за две вечери: разходи по категории, месечна графика и общ изглед за двама ни. Най-трудното беше да убедя AI-а да форматира сумите в евро. Какво бихте добавили?' WHERE id = 4;

UPDATE posts SET title = 'Lovable + Stripe: приемане на плащания в евро', slug = 'lovable-stripe-priemane-na-plashtaniya-v-evro', excerpt = 'Настройка на Stripe за EUR, тестови карти и какво да напишеш в промпта, за да стане от първия път.', body = 'След няколко неуспешни опита открих работеща последователност: първо създайте продуктите в Stripe ръчно, после опишете в промпта точните price ID-та. Тестовите карти на Stripe работят и за EUR. Внимавайте с валутата в checkout сесията — по подразбиране е USD.' WHERE id = 5;

UPDATE courses SET description = 'Реална база данни, вход с имейл и Google, Stripe плащания в евро.' WHERE sort = 3;
